parameters.jsCode:
// Sicheres Parsen des LLM-JSON aus 'KI: Anfrage extrahieren'. Bei ungültigem JSON:
// leerer, aber gültiger Fallback -> Angebots-Entwurf fragt im Text nach fehlenden Angaben,
// statt den Workflow abzubrechen.
let data = { kunde_name: '', leistung: '', budget_hinweis: '', kontakt_email: '' };
try {
  const parsed = JSON.parse($input.first().json.text);
  if (parsed && typeof parsed === 'object') data = { ...data, ...parsed };
} catch (e) { /* ungültiges LLM-JSON -> Fallback mit leeren Feldern */ }
const fromHeader = $('Neue Anfrage').item.json.from || '';
const emailMatch = fromHeader.match(/[^<\s]+@[^>\s]+/);
return [{
  json: {
    kunde_name: data.kunde_name || '',
    leistung: data.leistung || '',
    budget_hinweis: data.budget_hinweis || '',
    kontakt_email: data.kontakt_email || (emailMatch ? emailMatch[0] : fromHeader),
  },
}];

// Baut aus den Datenablage-Zeilen der Preisliste einen kompakten Text-Block fuer den
// offer/draft-Prompt ({{preisliste}}). Jede Zeile: { data: { leistung, preis, einheit?, hinweis? } }.
const rows = ($input.first().json.rows || []);
if (!rows.length) {
  return [{ json: { preisliste_text: 'Keine Preisliste hinterlegt — im Angebotstext transparent nachfragen, welche Leistung/Preis gemeint ist, statt zu raten.' } }];
}
const lines = rows.map((row) => {
  const d = row.data || {};
  const preis = d.preis ? `${d.preis}${d.einheit ? ' ' + d.einheit : ''}` : 'Preis auf Anfrage';
  return `- ${d.leistung || 'Leistung'}: ${preis}${d.hinweis ? ' (' + d.hinweis + ')' : ''}`;
}).join('\n');
return [{ json: { preisliste_text: lines } }];

